package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonArray;
import com.google.gson.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.util.Iterator;

class JsonTreeReaderTest {

  private JsonTreeReader jsonTreeReader;

  @BeforeEach
  void setUp() throws Exception {
    // Create a JsonArray and initialize JsonTreeReader with it
    JsonArray jsonArray = new JsonArray();
    // Add some elements to the array
    jsonArray.add("element1");
    jsonArray.add("element2");
    jsonTreeReader = new JsonTreeReader(jsonArray);

    // Push the JsonArray onto the stack manually to simulate internal state before beginArray
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = (Object[]) stackField.get(jsonTreeReader);
    stack[0] = jsonArray;
    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(jsonTreeReader, 1);

    // Set pathIndices array with initial values
    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = (int[]) pathIndicesField.get(jsonTreeReader);
    pathIndices[0] = -1;
  }

  @Test
  void testBeginArray_success() throws Exception {
    // Use reflection to override the private expect method to a no-op
    JsonTreeReader spyReader = spy(jsonTreeReader);

    Method expectMethod = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
    expectMethod.setAccessible(true);

    doAnswer(invocation -> {
      JsonToken token = invocation.getArgument(0);
      // Simulate expect checking that top of stack is BEGIN_ARRAY token
      assertEquals(JsonToken.BEGIN_ARRAY, token);
      return null;
    }).when(spyReader).expect(any());

    // Because expect is private, we cannot mock it directly with Mockito.
    // Instead, we replace it by reflection with a public method temporarily.

    // Use reflection to replace the private expect method with a public one via a proxy is complex.
    // Instead, use a workaround: create a subclass with overridden expect method.

    JsonTreeReader testReader = new JsonTreeReader(jsonTreeReader.peekStack()) {
      @Override
      protected void expect(JsonToken expected) throws IOException {
        assertEquals(JsonToken.BEGIN_ARRAY, expected);
      }
    };

    // Set up internal state of testReader same as spyReader
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = (Object[]) stackField.get(jsonTreeReader);
    stackField.set(testReader, stack);

    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(testReader, 1);

    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = (int[]) pathIndicesField.get(jsonTreeReader);
    pathIndicesField.set(testReader, pathIndices);

    testReader.beginArray();

    int stackSize = stackSizeField.getInt(testReader);
    assertEquals(2, stackSize);

    Object[] testStack = (Object[]) stackField.get(testReader);
    Object top = testStack[stackSize - 1];
    assertNotNull(top);
    assertTrue(top instanceof Iterator);

    int[] testPathIndices = (int[]) pathIndicesField.get(testReader);
    assertEquals(0, testPathIndices[stackSize - 1]);
  }

  @Test
  void testBeginArray_expectThrows() throws Exception {
    // Create a subclass that throws IOException in expect method
    JsonTreeReader testReader = new JsonTreeReader(jsonTreeReader.peekStack()) {
      @Override
      protected void expect(JsonToken expected) throws IOException {
        throw new IOException("Expected token not found");
      }
    };

    // Set up internal state of testReader same as jsonTreeReader
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = (Object[]) stackField.get(jsonTreeReader);
    stackField.set(testReader, stack);

    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(testReader, 1);

    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = (int[]) pathIndicesField.get(jsonTreeReader);
    pathIndicesField.set(testReader, pathIndices);

    IOException thrown = assertThrows(IOException.class, testReader::beginArray);
    assertEquals("Expected token not found", thrown.getMessage());
  }
}
